protected RefRecId populateVendInvoiceJour(CustVendTrans _vendTrans)
{
    LedgerJournalTrans ledgerJournalTransETG;
    RefRecId           origVendInvoiceJourRecId = next populateVendInvoiceJour(_vendTrans);

    if (common.TableId == tableNum(LedgerJournalTrans))
    {
        ledgerJournalTransETG = common;
        vendInvoiceJour.Qty   = ledgerJournalTransETG.Qty;
    }

    return origVendInvoiceJourRecId;
}
